import React from "react";

function AgendaDisplay({ agenda }) {
  return (
    <div className="agenda-display">
      <h2>Agenda</h2>
      <ol>
        {agenda?.map((item, idx) => (
          <li key={idx}>{item}</li>
        ))}
      </ol>
    </div>
  );
}

export default AgendaDisplay;
